// 1. Get Chat ID and User Name (Trigger ALWAYS runs, so this is 100% safe)
const triggerData = $('Telegram Trigger').first().json.message;
const chat_id = triggerData.chat.id;
const user_name = triggerData.from.first_name;

// 2. Safely get the message text (works for BOTH voice and text paths)
let message_text = $input.first().json.message_text;

// If it's missing (because Edit Fields dropped it), grab it from Trigger as fallback
if (!message_text) {
  message_text = triggerData.text || "Unknown message";
}

// 3. Parse Gemini's JSON response
let geminiText = $input.first().json.text;
geminiText = geminiText.replace(/```json/g, '').replace(/```/g, '').trim();
let parsed = JSON.parse(geminiText);

// 4. Return clean data
return [{
  json: {
    chat_id: chat_id,
    user_name: user_name,
    message_text: message_text,
    intent: parsed.intent,
    order_id: parsed.order_id,
    sentiment: parsed.sentiment,
    summary: parsed.summary
  }
}];

