const fakeDatabase = [
  {
    id: "1159",
    name: "#1159",
    financial_status: "paid",
    fulfillment_status: "in_transit",
    total_price: "120",
    currency: "INR",
    tracking_number: "1Z999AA10123456784",
    line_items: [{ title: "Cute Crochet", quantity: 1 }]
  },
  {
    id: "1140",
    name: "#1140",
    financial_status: "pending",
    fulfillment_status: "shipped",
    total_price: "300",
    currency: "INR",
    tracking_number: "1K999DD10123456784",
    line_items: [{ title: "Cute Crochet Teddy", quantity: 1 }]
  }
];

// 2. Safely get the Order ID (check if it exists first)
const rawOrderId = $input.first().json.order_id;
const requestedId = rawOrderId ? rawOrderId.toString() : null;

// 3. If no order ID was found, return early so Gemini can ask for it
if (!requestedId) {
  return [{ 
    json: { 
      error: "no_order_id" 
    } 
  }];
}

// 4. Find the matching order
const orderDetails = fakeDatabase.find(order => order.id === requestedId);

// 5. Return the order or "not found" error
if (orderDetails) {
  return [{ json: orderDetails }];
} else {
  return [{ 
    json: { 
      error: "order_not_found", 
      requested_id: requestedId 
    } 
  }];
}
